class CommandPalette extends HTMLElement{constructor(){super();this.attachShadow({mode: 'open'});this.commands=[];this.isOpen=false;this.selectedIndex=0;}static get observedAttributes(){return ['placeholder'];}connectedCallback(){this.render();this.initCommands();this.initKeyboard();this.initSearch();}initCommands(){this.commands=[{id: 'dashboard',label: 'Dashboard',icon: 'dashboard',shortcut: 'G D',action:()=>this.navigate('/admin/dashboard.html')},{id: 'campaigns',label: 'Campaigns',icon: 'campaign',shortcut: 'G C',action:()=>this.navigate('/admin/campaigns.html')},{id: 'leads',label: 'Leads',icon: 'ads_click',shortcut: 'G L',action:()=>this.navigate('/admin/leads.html')},{id: 'analytics',label: 'Analytics',icon: 'analytics',shortcut: 'G A',action:()=>this.navigate('/admin/analytics.html')},{id: 'settings',label: 'Settings',icon: 'settings',shortcut: 'G S',action:()=>this.navigate('/admin/settings.html')},{id: 'new-project',label: 'New Project',icon: 'add_circle',shortcut: 'N P',action:()=>this.navigate('/admin/projects.html?action=new')},{id: 'new-campaign',label: 'New Campaign',icon: 'add_circle_outline',shortcut: 'N C',action:()=>this.navigate('/admin/campaigns.html?action=new')},{id: 'dark-mode',label: 'Toggle Dark Mode',icon: 'dark_mode',shortcut: 'D M',action:()=>window.MekongAdmin?.ThemeManager?.toggle()},{id: 'notifications',label: 'Notifications',icon: 'notifications',shortcut: 'N N',action:()=>this.navigate('/admin/notifications.html')},{id: 'help',label: 'Help&Support',icon: 'help',shortcut: 'F1',action:()=>this.navigate('/admin/help.html')},];document.addEventListener('keydown',(e)=>{if((e.metaKey||e.ctrlKey)&&e.key==='k'){e.preventDefault();this.toggle();}if(e.key==='Escape'&&this.isOpen){this.close();}});}initKeyboard(){const input=this.shadowRoot.querySelector('input');const results=this.shadowRoot.querySelector('.results');input.addEventListener('keydown',(e)=>{const items=results.querySelectorAll('.result-item');if(e.key==='ArrowDown'){e.preventDefault();this.selectedIndex=Math.min(this.selectedIndex+1,items.length-1);this.updateSelection(items);}else if(e.key==='ArrowUp'){e.preventDefault();this.selectedIndex=Math.max(this.selectedIndex-1,0);this.updateSelection(items);}else if(e.key==='Enter'){e.preventDefault();if(items[this.selectedIndex]){items[this.selectedIndex].click();}}});}initSearch(){const input=this.shadowRoot.querySelector('input');input.addEventListener('input',(e)=>{const query=e.target.value.toLowerCase();this.renderResults(this.filterCommands(query));});}filterCommands(query){if(!query)return this.commands;return this.commands.filter(cmd=>cmd.label.toLowerCase().includes(query)||cmd.id.toLowerCase().includes(query));}updateSelection(items){items.forEach((item,i)=>{item.classList.toggle('selected',i===this.selectedIndex);});}navigate(path){this.close();window.location.href=path;}toggle(){if(this.isOpen){this.close();}else{this.open();}}open(){this.isOpen=true;const overlay=this.shadowRoot.querySelector('.overlay');const modal=this.shadowRoot.querySelector('.modal');overlay.style.display='block';setTimeout(()=>{modal.style.opacity='1';modal.style.transform='scale(1)';},10);this.shadowRoot.querySelector('input').focus();this.shadowRoot.querySelector('input').value='';this.selectedIndex=0;this.renderResults(this.commands);}close(){const overlay=this.shadowRoot.querySelector('.overlay');const modal=this.shadowRoot.querySelector('.modal');modal.style.opacity='0';modal.style.transform='scale(0.95)';setTimeout(()=>{overlay.style.display='none';this.isOpen=false;},150);}render(){const placeholder=this.getAttribute('placeholder')||'Search commands...';this.shadowRoot.innerHTML=`<style>:host{display: block;}.overlay{display: none;position: fixed;top: 0;left: 0;right: 0;bottom: 0;background: rgba(0,0,0,0.5);backdrop-filter: blur(4px);z-index: 9999;}.modal{position: fixed;top: 15%;left: 50%;transform: translateX(-50%)scale(0.95);width: 90%;max-width: 560px;background: var(--surface,#fff);border-radius: 16px;box-shadow: 0 25px 50px-12px rgba(0,0,0,0.25);overflow: hidden;transition: all 0.15s ease;opacity: 0;}.search-bar{display: flex;align-items: center;padding: 16px 20px;border-bottom: 1px solid var(--border,#e5e7eb);}.search-bar .material-symbols-outlined{color: var(--muted,#9ca3af);margin-right: 12px;}.search-bar input{flex: 1;border: none;outline: none;font-size: 16px;background: transparent;color: var(--text,#111827);}.search-bar input::placeholder{color: var(--muted,#9ca3af);}.shortcut-hint{font-size: 12px;color: var(--muted,#9ca3af);background: var(--surface-2,#f3f4f6);padding: 4px 8px;border-radius: 6px;}.results{max-height: 400px;overflow-y: auto;padding: 8px;}.result-item{display: flex;align-items: center;padding: 12px 16px;border-radius: 8px;cursor: pointer;transition: background 0.15s;}.result-item:hover,.result-item.selected{background: var(--primary,rgba(6,182,212,0.1));}.result-item .material-symbols-outlined{margin-right: 12px;color: var(--primary,#06b6d4);}.result-item .label{flex: 1;font-size: 14px;color: var(--text,#111827);}.result-item .shortcut{font-size: 11px;color: var(--muted,#9ca3af);background: var(--surface-2,#f3f4f6);padding: 2px 6px;border-radius: 4px;}.empty-state{padding: 40px 20px;text-align: center;color: var(--muted,#9ca3af);}</style><div class="overlay" @click="${()=>this.close()}"></div><div class="modal"><div class="search-bar"><span class="material-symbols-outlined">search</span><input type="text" placeholder="${placeholder}" aria-label="Search commands"><span class="shortcut-hint">⌘K</span></div><div class="results"></div></div>`;}renderResults(commands){const results=this.shadowRoot.querySelector('.results');if(commands.length===0){results.innerHTML=`<div class="empty-state"><span class="material-symbols-outlined" style="font-size: 48px;margin-bottom: 8px;">search_off</span><p>No results found</p></div>`;return;}results.innerHTML=commands.map((cmd,i)=>`<div class="result-item ${i===0 ? 'selected' : ''}" tabindex="0"><span class="material-symbols-outlined">${cmd.icon}</span><span class="label">${cmd.label}</span><span class="shortcut">${cmd.shortcut}</span></div>`).join('');results.querySelectorAll('.result-item').forEach((item,i)=>{item.addEventListener('click',()=>{commands[i].action();});});}}if(!customElements.get('command-palette')){customElements.define('command-palette',CommandPalette);}